# =============================================================================
#  PYCART SYSTEM  (encode / decode / verify / run)
# =============================================================================

def cart_encode(py_source, meta):
    """Pack Python source + metadata into a PyCart dict."""
    code_b64 = base64.b64encode(py_source.encode("utf-8")).decode("ascii")
    chk = hashlib.sha256(py_source.encode("utf-8")).hexdigest()[:16]
    full_meta = dict(meta)
    full_meta.setdefault("engine", ENGINE_VER)
    full_meta["checksum"] = chk
    full_meta["size"] = len(py_source)
    return {"schema": CART_SCHEMA_VERSION, "meta": full_meta, "code": code_b64}

def cart_decode(cart):
    """Decode a PyCart dict back into Python source string."""
    return base64.b64decode(cart["code"]).decode("utf-8")

def cart_verify(cart):
    """Verify SHA-256 checksum of cart."""
    src = cart_decode(cart)
    chk = hashlib.sha256(src.encode("utf-8")).hexdigest()[:16]
    return chk == cart.get("meta", {}).get("checksum", "")

def cart_save(cart, path):
    with open(path, "w", encoding="utf-8") as f:
        json.dump(cart, f, indent=2)

def cart_load(path):
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)

def cart_run_subprocess(cart, on_done=None):
    """Run a PyCart in a fresh Python subprocess (clean isolation)."""
    src = cart_decode(cart) if isinstance(cart, dict) else cart
    fd, tmp_path = tempfile.mkstemp(suffix=".py", prefix="v01d_cart_")
    try:
        with os.fdopen(fd, "w", encoding="utf-8") as f:
            f.write(src)
        proc = subprocess.Popen(
            [sys.executable, tmp_path],
            stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
            text=True, cwd=str(WORKSPACE)
        )
        def waiter():
            try:
                out, _ = proc.communicate()
                rc = proc.returncode
            except Exception as e:
                out, rc = str(e), -1
            try:
                os.unlink(tmp_path)
            except Exception:
                pass
            if on_done:
                on_done(rc, out or "")
        threading.Thread(target=waiter, daemon=True).start()
        return proc
    except Exception as e:
        try: os.unlink(tmp_path)
        except Exception: pass
        if on_done: on_done(-1, str(e))
        return None

def list_user_carts():
    """List user-saved .pycart.json files in workspace."""
    return sorted(CARTS_DIR.glob("*.pycart.json"))

def list_all_carts():
    """Return merged dict of {id: cart} for embedded + user carts."""
    out = dict(EMBEDDED_CARTS)
    for p in list_user_carts():
        try:
            c = cart_load(p)
            cid = c.get("meta", {}).get("id") or p.stem
            # User carts get _user suffix to avoid collisions with embedded
            if cid in out:
                cid = cid + "_user"
            c["meta"]["_path"] = str(p)
            out[cid] = c
        except Exception:
            pass
    return out

# =============================================================================
#  WIDGET HELPERS — phosphor style
# =============================================================================

def style_btn(parent, text, cmd, accent=False, big=False, **kw):
    """Phosphor-style button."""
    fg = C["accent"] if accent else C["mid"]
    pady = 6 if big else 3
    padx = 12 if big else 8
    font = FNTB if big else FNTS
    b = tk.Button(parent, text=text, bg=C["ghost"], fg=fg, font=font,
                  relief="flat", bd=0, padx=padx, pady=pady,
                  activebackground=C["border"], activeforeground=C["hi"],
                  cursor="hand2", command=cmd, **kw)
    return b

def style_label(parent, text, **kw):
    return tk.Label(parent, text=text, bg=C["bg"], fg=C["mid"], font=FNT, **kw)

def style_text(parent, height=10, **kw):
    t = tk.Text(parent, bg=C["ghost"], fg=C["hi"], font=FNT,
                insertbackground=C["cursor"], relief="flat", bd=0,
                wrap="none", undo=True, maxundo=200, height=height,
                selectbackground=C["accent"], selectforeground=C["bg"], **kw)
    return t

def style_listbox(parent, **kw):
    lb = tk.Listbox(parent, bg=C["ghost"], fg=C["hi"], font=FNT,
                    selectbackground=C["accent"], selectforeground=C["bg"],
                    relief="flat", bd=0, highlightthickness=1,
                    highlightbackground=C["border"],
                    activestyle="none", **kw)
    return lb

def style_scrollbar(parent, **kw):
    return tk.Scrollbar(parent, bg=C["ghost"], troughcolor=C["bg"],
                        bd=0, relief="flat", activebackground=C["border"], **kw)

def divider(parent, **kw):
    return tk.Frame(parent, bg=C["border"], height=1, **kw)

def vdivider(parent, **kw):
    return tk.Frame(parent, bg=C["border"], width=1, **kw)

def add_clipboard_bindings(text_widget):
    """Add Ctrl+C/X/V + right-click menu to a Text widget."""
    def _cut(e=None):
        try: text_widget.event_generate("<<Cut>>")
        except: pass
    def _copy(e=None):
        try: text_widget.event_generate("<<Copy>>")
        except: pass
    def _paste(e=None):
        try: text_widget.event_generate("<<Paste>>")
        except: pass
    def _selectall(e=None):
        text_widget.tag_add("sel", "1.0", "end")
        return "break"
    text_widget.bind("<Control-c>", _copy)
    text_widget.bind("<Control-C>", _copy)
    text_widget.bind("<Control-x>", _cut)
    text_widget.bind("<Control-X>", _cut)
    text_widget.bind("<Control-v>", _paste)
    text_widget.bind("<Control-V>", _paste)
    text_widget.bind("<Control-a>", _selectall)
    text_widget.bind("<Control-A>", _selectall)
    menu = tk.Menu(text_widget, tearoff=0, bg=C["ghost"], fg=C["hi"],
                   activebackground=C["border"], activeforeground=C["accent"])
    menu.add_command(label="Cut", command=_cut)
    menu.add_command(label="Copy", command=_copy)
    menu.add_command(label="Paste", command=_paste)
    menu.add_separator()
    menu.add_command(label="Select All", command=_selectall)
    def _popup(e):
        try: menu.tk_popup(e.x_root, e.y_root)
        finally: menu.grab_release()
    text_widget.bind("<Button-3>", _popup)

