class MasterSDK:
    """V01D MASTER SDK — single-window launcher with tabs."""

    def __init__(self):
        self.root = tk.Tk()
        self.root.title(f"{SDK_NAME} v{SDK_VERSION} — {SDK_TAGLINE}")
        self.root.configure(bg=C["bg"])
        self.root.geometry("1280x820")
        self.root.minsize(960, 640)

        # State
        self.current_filter = "all"
        self.current_file = None
        self.running_procs = []   # track launched subprocesses
        self.workshop_cart = None # cart being edited
        self.search_term = ""

        self._build_root_chrome()
        self._build_tabs()
        self._build_status_bar()

        # Initial selection
        self._select_tab("library")

        # Window close handler
        self.root.protocol("WM_DELETE_WINDOW", self._on_close)

    # ── ROOT CHROME (header strip with title + tab buttons) ─────────────────
    def _build_root_chrome(self):
        head = tk.Frame(self.root, bg=C["bg"])
        head.pack(fill="x", padx=12, pady=(10, 0))

        # Title row
        title_row = tk.Frame(head, bg=C["bg"])
        title_row.pack(fill="x")
        tk.Label(title_row, text="V01D", bg=C["bg"], fg=C["accent"],
                 font=FNTHH).pack(side="left")
        tk.Label(title_row, text=" MASTER SDK ", bg=C["bg"], fg=C["hi"],
                 font=FNTHH).pack(side="left")
        tk.Label(title_row, text=f"v{SDK_VERSION}", bg=C["bg"], fg=C["dim"],
                 font=FNTM).pack(side="left", pady=(8, 0))
        tk.Label(title_row, text=f"  ·  {len(EMBEDDED_CARTS)} embedded apps",
                 bg=C["bg"], fg=C["accent2"], font=FNTS).pack(side="left", pady=(10, 0))
        tk.Label(title_row, text=SDK_TAGLINE, bg=C["bg"], fg=C["dim"],
                 font=FNTS).pack(side="right", pady=(10, 0))

        divider(head).pack(fill="x", pady=(8, 0))

        # Tab strip
        tab_bar = tk.Frame(self.root, bg=C["bg"])
        tab_bar.pack(fill="x", padx=12, pady=(6, 6))

        self.tab_buttons = {}
        self.tab_frames = {}

        tabs = [
            ("library",   "📚 LIBRARY"),
            ("engines",   "🎮 GFX ENGINES"),
            ("ide",       "💻 IDE"),
            ("workshop",  "📦 WORKSHOP"),
            ("about",     "ℹ ABOUT"),
        ]
        for key, label in tabs:
            b = tk.Button(tab_bar, text=label, bg=C["bg"], fg=C["dim"],
                          font=FNTB, relief="flat", bd=0, padx=14, pady=6,
                          activebackground=C["bg"], activeforeground=C["accent"],
                          cursor="hand2",
                          command=lambda k=key: self._select_tab(k))
            b.pack(side="left", padx=(0, 4))
            self.tab_buttons[key] = b

        divider(self.root).pack(fill="x", padx=12)

    # ── TAB FRAMES ──────────────────────────────────────────────────────────
    def _build_tabs(self):
        self.body = tk.Frame(self.root, bg=C["bg"])
        self.body.pack(fill="both", expand=True, padx=12, pady=8)

        # Build each tab's frame (only one visible at a time)
        self.tab_frames["library"]  = self._build_library_tab()
        self.tab_frames["engines"]  = self._build_engines_tab()
        self.tab_frames["ide"]      = self._build_ide_tab()
        self.tab_frames["workshop"] = self._build_workshop_tab()
        self.tab_frames["about"]    = self._build_about_tab()

    def _select_tab(self, key):
        for k, frame in self.tab_frames.items():
            if k == key:
                frame.pack(fill="both", expand=True)
                self.tab_buttons[k].config(fg=C["accent"])
            else:
                frame.pack_forget()
                self.tab_buttons[k].config(fg=C["dim"])
        if hasattr(self, "_status_var"):
            self._status_var.set(f"[ {key.upper()} ]  ready")

    # ── STATUS BAR ──────────────────────────────────────────────────────────
    def _build_status_bar(self):
        bar = tk.Frame(self.root, bg=C["panel"])
        bar.pack(fill="x", side="bottom")
        divider(self.root).pack(fill="x", side="bottom")
        self._status_var = tk.StringVar(value="ready")
        tk.Label(bar, textvariable=self._status_var, bg=C["panel"], fg=C["dim"],
                 font=FNTXS, anchor="w").pack(side="left", padx=10, pady=4)
        tk.Label(bar, text=f"workspace: {WORKSPACE}", bg=C["panel"], fg=C["deep"],
                 font=FNTXS).pack(side="right", padx=10, pady=4)

    def _status(self, msg):
        if hasattr(self, "_status_var"):
            self._status_var.set(msg)

    # =========================================================================
    #  TAB: LIBRARY  (grid of all embedded apps with filter & launch)
    # =========================================================================
    def _build_library_tab(self):
        f = tk.Frame(self.body, bg=C["bg"])

        # Top: search + filter pills
        top = tk.Frame(f, bg=C["bg"])
        top.pack(fill="x", pady=(0, 8))
        tk.Label(top, text="🔍", bg=C["bg"], fg=C["dim"],
                 font=FNTM).pack(side="left", padx=(0, 4))
        self.search_var = tk.StringVar()
        search_e = tk.Entry(top, textvariable=self.search_var, bg=C["ghost"],
                            fg=C["hi"], insertbackground=C["cursor"],
                            relief="flat", bd=0, font=FNT, width=30)
        search_e.pack(side="left", ipady=4, padx=(0, 14))
        self.search_var.trace_add("write",
            lambda *a: self._library_render())

        # Filter pills
        self.filter_var = tk.StringVar(value="all")
        filters = [("all","ALL"), ("engine","ENGINES"), ("sdk","SDK"),
                   ("tool","TOOLS"), ("ai","AI"), ("creative","CREATIVE"),
                   ("game","GAMES"), ("demo","DEMOS"), ("user","MY CARTS")]
        for tag, label in filters:
            b = tk.Radiobutton(top, text=label, variable=self.filter_var,
                               value=tag, bg=C["bg"], fg=C["dim"],
                               selectcolor=C["bg"], activebackground=C["bg"],
                               activeforeground=C["accent"], font=FNTS,
                               indicatoron=0, relief="flat", bd=0,
                               padx=8, pady=3,
                               command=self._library_render)
            b.pack(side="left", padx=2)

        # Action row
        act = tk.Frame(top, bg=C["bg"])
        act.pack(side="right")
        style_btn(act, "↻ Refresh", self._library_render).pack(side="left", padx=2)
        style_btn(act, "+ Import .pycart.json",
                  self._library_import_cart, accent=True).pack(side="left", padx=2)

        divider(f).pack(fill="x")

        # Scrollable card grid
        body = tk.Frame(f, bg=C["bg"])
        body.pack(fill="both", expand=True, pady=8)

        self.lib_canvas = tk.Canvas(body, bg=C["bg"], highlightthickness=0)
        self.lib_canvas.pack(side="left", fill="both", expand=True)
        sb = style_scrollbar(body, orient="vertical",
                             command=self.lib_canvas.yview)
        sb.pack(side="right", fill="y")
        self.lib_canvas.configure(yscrollcommand=sb.set)

        self.lib_inner = tk.Frame(self.lib_canvas, bg=C["bg"])
        self.lib_inner_id = self.lib_canvas.create_window(
            (0, 0), window=self.lib_inner, anchor="nw")

        def _on_lib_resize(event):
            self.lib_canvas.configure(scrollregion=self.lib_canvas.bbox("all"))
            self.lib_canvas.itemconfig(self.lib_inner_id, width=event.width)
        self.lib_canvas.bind("<Configure>", _on_lib_resize)
        self.lib_inner.bind(
            "<Configure>",
            lambda e: self.lib_canvas.configure(
                scrollregion=self.lib_canvas.bbox("all")))

        # Mousewheel
        def _on_wheel(event):
            self.lib_canvas.yview_scroll(int(-1 * (event.delta / 120)), "units")
        self.lib_canvas.bind_all("<MouseWheel>", _on_wheel)

        self._library_render()
        return f

    def _library_render(self):
        """Render the app cards based on current filter + search."""
        for w in self.lib_inner.winfo_children():
            w.destroy()

        carts = list_all_carts()
        flt = self.filter_var.get() if hasattr(self, "filter_var") else "all"
        term = self.search_var.get().lower().strip() if hasattr(self, "search_var") else ""

        items = []
        for cid, cart in carts.items():
            meta = cart.get("meta", {})
            tag = meta.get("tag", "tool")
            is_user = "_path" in meta
            if flt == "user" and not is_user:
                continue
            if flt not in ("all", "user") and tag != flt:
                continue
            if term:
                hay = (meta.get("title","") + " " + meta.get("desc","") + " " +
                       meta.get("genre","") + " " + cid).lower()
                if term not in hay:
                    continue
            items.append((cid, cart))

        # Sort: engines first, then alphabetical
        items.sort(key=lambda kv: (kv[1]["meta"].get("tag","z") != "engine",
                                    kv[1]["meta"].get("title","")))

        # 3-column grid
        cols = 3
        for i, (cid, cart) in enumerate(items):
            r, c = divmod(i, cols)
            self._render_card(self.lib_inner, cart, cid, r, c)
        for c in range(cols):
            self.lib_inner.columnconfigure(c, weight=1, uniform="col")

        if not items:
            tk.Label(self.lib_inner, text="(no apps match)",
                     bg=C["bg"], fg=C["deep"], font=FNT).grid(row=0, column=0,
                     padx=20, pady=20)

        self._status(f"Library: {len(items)} app(s) shown")

    def _render_card(self, parent, cart, cid, row, col):
        meta = cart.get("meta", {})
        is_user = "_path" in meta

        card = tk.Frame(parent, bg=C["panel"], bd=1, relief="flat",
                        highlightthickness=1, highlightbackground=C["border"])
        card.grid(row=row, column=col, padx=6, pady=6, sticky="nsew", ipadx=4, ipady=4)

        # Top row: icon + title
        top = tk.Frame(card, bg=C["panel"])
        top.pack(fill="x", padx=10, pady=(8, 2))
        tk.Label(top, text=meta.get("icon","■"), bg=C["panel"],
                 fg=C["accent"], font=("Courier New", 18, "bold")).pack(side="left")
        title_box = tk.Frame(top, bg=C["panel"])
        title_box.pack(side="left", fill="x", expand=True, padx=(8, 0))
        tk.Label(title_box, text=meta.get("title","Untitled"),
                 bg=C["panel"], fg=C["hi"], font=FNTH,
                 anchor="w", justify="left").pack(fill="x", anchor="w")
        sub = f"{meta.get('genre','')}  ·  v{meta.get('version','?')}"
        if is_user: sub = "[USER] " + sub
        tk.Label(title_box, text=sub, bg=C["panel"], fg=C["dim"],
                 font=FNTXS, anchor="w").pack(fill="x", anchor="w")

        # Description
        desc = meta.get("desc", "")
        wrap = textwrap.fill(desc, 60)
        tk.Label(card, text=wrap, bg=C["panel"], fg=C["mid"], font=FNTS,
                 justify="left", anchor="w", wraplength=360).pack(
                 fill="x", padx=10, pady=(2, 6))

        # Stats row
        stats = tk.Frame(card, bg=C["panel"])
        stats.pack(fill="x", padx=10, pady=(0, 6))
        size_kb = meta.get("size", 0) / 1024
        tk.Label(stats, text=f"📦 {size_kb:.1f} KB", bg=C["panel"], fg=C["deep"],
                 font=FNTXS).pack(side="left")
        tk.Label(stats, text=f"  ·  ✓ {meta.get('checksum','???')[:8]}",
                 bg=C["panel"], fg=C["deep"], font=FNTXS).pack(side="left")

        # Buttons
        btns = tk.Frame(card, bg=C["panel"])
        btns.pack(fill="x", padx=10, pady=(2, 8))
        style_btn(btns, "▶ Run", lambda c=cart: self._run_cart(c),
                  accent=True).pack(side="left", padx=2)
        style_btn(btns, "📜 Source",
                  lambda c=cart: self._view_cart_source(c)).pack(side="left", padx=2)
        style_btn(btns, "📤 Export .py",
                  lambda c=cart: self._export_cart_py(c)).pack(side="left", padx=2)
        style_btn(btns, "📦 Save Cart",
                  lambda c=cart: self._export_cart_json(c)).pack(side="left", padx=2)

    # ── LIBRARY ACTIONS ─────────────────────────────────────────────────────
    def _run_cart(self, cart):
        meta = cart.get("meta", {})
        title = meta.get("title", "cart")
        if not cart_verify(cart):
            if not messagebox.askyesno(
                "Checksum mismatch",
                f"PyCart '{title}' failed integrity check. Run anyway?"):
                return
        self._status(f"▶ Launching {title}...")

        def on_done(rc, out):
            tail = out[-2000:] if out else ""
            msg = f"[{title}] exited rc={rc}"
            self.root.after(0, lambda: self._status(msg))
            if rc != 0 and tail.strip():
                self.root.after(0, lambda: self._show_error_dialog(title, rc, tail))

        cart_run_subprocess(cart, on_done=on_done)

    def _show_error_dialog(self, title, rc, output):
        d = tk.Toplevel(self.root)
        d.title(f"Output — {title}")
        d.configure(bg=C["bg"])
        d.geometry("760x460")
        tk.Label(d, text=f"{title} exited with code {rc}",
                 bg=C["bg"], fg=C["warn"], font=FNTB).pack(padx=10, pady=10, anchor="w")
        txt = scrolledtext.ScrolledText(d, bg=C["ghost"], fg=C["mid"],
                                        font=FNT, relief="flat", bd=0)
        txt.pack(fill="both", expand=True, padx=10, pady=(0, 10))
        txt.insert("1.0", output)
        txt.configure(state="disabled")
        style_btn(d, "Close", d.destroy).pack(pady=(0, 10))

    def _view_cart_source(self, cart):
        src = cart_decode(cart)
        meta = cart.get("meta", {})
        title = meta.get("title", "Source")

        d = tk.Toplevel(self.root)
        d.title(f"Source — {title}")
        d.configure(bg=C["bg"])
        d.geometry("960x680")

        # Header
        h = tk.Frame(d, bg=C["bg"])
        h.pack(fill="x", padx=10, pady=8)
        tk.Label(h, text=f"{meta.get('icon','■')}  {title}",
                 bg=C["bg"], fg=C["hi"], font=FNTH).pack(side="left")
        tk.Label(h, text=f"   {meta.get('size',0):,} bytes  ·  "
                          f"sha256:{meta.get('checksum','?')}",
                 bg=C["bg"], fg=C["dim"], font=FNTS).pack(side="left", pady=(6,0))

        # Buttons
        btns = tk.Frame(d, bg=C["bg"])
        btns.pack(fill="x", padx=10)
        def _copy_all():
            d.clipboard_clear()
            d.clipboard_append(src)
            self._status(f"Copied {len(src):,} bytes to clipboard")
        def _send_to_ide():
            self._select_tab("ide")
            self._ide_load_text(src, name=meta.get("title","cart")+".py")
            d.destroy()
        def _save_as():
            p = filedialog.asksaveasfilename(
                defaultextension=".py",
                initialfile=meta.get("id","cart") + ".py",
                filetypes=[("Python","*.py"), ("All","*.*")])
            if p:
                Path(p).write_text(src, encoding="utf-8")
                self._status(f"Saved to {p}")

        style_btn(btns, "📋 Copy All", _copy_all, accent=True).pack(side="left", padx=2)
        style_btn(btns, "💻 Open in IDE", _send_to_ide).pack(side="left", padx=2)
        style_btn(btns, "💾 Save As .py...", _save_as).pack(side="left", padx=2)
        style_btn(btns, "▶ Run", lambda: self._run_cart(cart)).pack(side="left", padx=2)
        style_btn(btns, "Close", d.destroy).pack(side="right", padx=2)

        # Source view
        body = tk.Frame(d, bg=C["bg"])
        body.pack(fill="both", expand=True, padx=10, pady=10)
        sb = style_scrollbar(body, orient="vertical")
        sb.pack(side="right", fill="y")
        sbx = style_scrollbar(body, orient="horizontal")
        sbx.pack(side="bottom", fill="x")
        txt = style_text(body, height=30)
        txt.pack(fill="both", expand=True)
        txt.configure(yscrollcommand=sb.set, xscrollcommand=sbx.set)
        sb.config(command=txt.yview)
        sbx.config(command=txt.xview)
        txt.insert("1.0", src)
        add_clipboard_bindings(txt)

    def _export_cart_py(self, cart):
        src = cart_decode(cart)
        meta = cart.get("meta", {})
        p = filedialog.asksaveasfilename(
            defaultextension=".py",
            initialdir=str(EXPORTS_DIR),
            initialfile=meta.get("id", "cart") + ".py",
            filetypes=[("Python","*.py"), ("All","*.*")])
        if p:
            Path(p).write_text(src, encoding="utf-8")
            self._status(f"Exported {meta.get('title')} → {p}")

    def _export_cart_json(self, cart):
        meta = cart.get("meta", {})
        p = filedialog.asksaveasfilename(
            defaultextension=".pycart.json",
            initialdir=str(CARTS_DIR),
            initialfile=meta.get("id","cart") + ".pycart.json",
            filetypes=[("PyCart","*.pycart.json"), ("All","*.*")])
        if p:
            cart_save(cart, p)
            self._status(f"Cart saved → {p}")

    def _library_import_cart(self):
        p = filedialog.askopenfilename(
            title="Import PyCart",
            initialdir=str(CARTS_DIR),
            filetypes=[("PyCart","*.pycart.json"), ("All","*.*")])
        if not p:
            return
        try:
            cart = cart_load(p)
            # Copy into carts dir if not already
            target = CARTS_DIR / Path(p).name
            if Path(p).resolve() != target.resolve():
                shutil.copy2(p, target)
            self._library_render()
            self.filter_var.set("user")
            self._library_render()
            self._status(f"Imported {Path(p).name}")
        except Exception as e:
            messagebox.showerror("Import failed", str(e))

