        act.pack(fill="x")
        style_btn(left, "🔍 PREVIEW META", self._ws_preview).pack(fill="x", pady=2)
        style_btn(left, "♻ Reset form", self._ws_reset).pack(fill="x", pady=2)

        # ── SOURCE PASTE (right) ──
